var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"도주발생. 도주발생.","JPN":"逃走発生。逃走発生。","ENG":"We have a prison break in progress. I repeat, we have a prison break in progress.","TWN":"發生逃獄，發生逃獄。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"제 2 시립교도소에서 수감자가 탈옥했습니다.","JPN":"第2市立刑務所から受刑者が脱獄しました。","ENG":"A prisoner escaped the Second City Penitentiary.","TWN":"第二市立監獄有囚犯越獄。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"수감자는 엘릭서를 밀반입하여 각성한 뒤 교도소 벽을 부수고 탈출한 것으로 추정됩니다.","JPN":"受刑者はエリクサーを密かに持ち込み覚醒した後、\\n刑務所の壁を壊して脱出したと推定されます。","ENG":"The suspect is assumed to have smuggled Elixir into the facility and awakened powers before breaking the walls and escaping.","TWN":"推測受刑人是偷渡聖水覺醒後，打破監獄牆壁越獄的。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"특이사항으로는 보행속도가 차량을 앞설 정도로 빠르다는 점. 체포 시 유의하십시오.","JPN":"特異な点は、歩行速度が車両を追い越すほど速いということです。\\n逮捕の際はご注意ください。","ENG":"Be advised that the suspect can move faster than a car. Please use caution when engaging.","TWN":"特別注意，受刑人的步行速度比車輛還快，逮捕時請小心。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"거기 서라! 범죄자!","JPN":"待て！　犯罪者！","ENG":"Freeze! Criminal!","TWN":"站住！犯罪者！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"순순히 체포되지 않으면 쓴 맛을 보게 될 거다!","JPN":"大人しく逮捕に応じないと、痛い目に合うから！","ENG":"If you resist arrest, you'll be sorry!","TWN":"如果你不乖乖逮捕歸案的話，可是會吃到苦頭的。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"흥! 카운터인가 본데, 그래 봐야 내 속도를 따라올 순 없을걸?","JPN":"ふん！　カウンターのようだけど、どうせ俺の速さには追いつけないぞ！","ENG":"Hmph! You're a Counter, eh? Talk all you want, but you'll never be able to catch me!","TWN":"哼！妳看起來雖然是制裁者，但也跟不上我的速度了吧？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"하하하! 뒤에서 내 엉덩이나 감상하라고 이 느림보야......","JPN":"ははは！　後ろで俺のケツでも鑑賞してろよ、こののろま……","ENG":"Hah hah hah! Just watch my butt as I run to freedom, you slow fool!","TWN":"哈哈哈！妳就在後面欣賞我的屁股吧，妳這隻蝸牛……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"우와아악!!!","JPN":"うわああっ！！！","ENG":"Gaaaah!","TWN":"哇啊啊啊！！！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇게 느려서 어디 도망은 치겠니?","JPN":"そんな遅い足で逃げ切れると思った？","ENG":"Aren't you too slow to run away?","TWN":"你速度這麼慢，是想逃到哪裡去呀？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"크윽, 어, 어떻게 그런 낡은 경찰차 따위로 날 따라잡은 거지......?","JPN":"くうっ、そ、そのぼろいパトカーでどうやって俺に追いついたんだ……","ENG":"H-how did you catch up with me with that raggedy patrol car?","TWN":"唔，這種老舊警車怎麼可能追得上我……？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이 정도야 간단하지. 경찰청 베스트 드라이버를 얕보지 말라고.","JPN":"このくらい簡単よ。警察庁のベストドライバーを甘く見ないことね。","ENG":"Oh, that was easy. Nothing the best driver in the entire police force can't handle.","TWN":"我可是警察廳的最強車手，不要小看我喔。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그보다 좀 포기하지 그래? 이제 슬슬 피곤하다, 야.","JPN":"それより、いい加減諦めたらどう？　そろそろ疲れてきたんだけど。","ENG":"Anyway, why don't you give up already? You're really starting to test my patience.","TWN":"話說回來，你現在該放棄了吧？我差不多覺得有點累了，喂。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"웃기지 마! 내가 잡힐 것 같아?","JPN":"ふざけるな！　俺が捕まると思うか？","ENG":"Don’t make me laugh! You think you can catch me?","TWN":"開什麼玩笑！妳以為我會被逮住嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"더 빨리 달릴 수도 있다고!","JPN":"もっと速く走れるんだぜ！","ENG":"I can run even faster!","TWN":"我還能跑得更快！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시끄러워! 술래잡기는 끝났다. 범죄자!","JPN":"うるさい！　お遊びもここまでだ、犯罪者！","ENG":"Oh, shut it. No more hide and seek, criminal!","TWN":"吵死了！躲貓貓遊戲已經結束了，犯罪者！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"변호사 선임하고, 묵비권 행사할 준비나 하시지!","JPN":"弁護士を選任して、黙秘権を行使する準備でもしなさい！","ENG":"Just prepare to hire a lawyer and remain silent!","TWN":"你還是準備請個律師，行使你的沉默權吧！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};